  ('medical-tech-moex-21058', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '由於德國麻疹病毒的培養費時費事，一般建議病人做抗體檢查，目前普遍採用的方法是下列何者？ 酵素免疫分析（ELISA）   血球凝集抑制試驗（HI） 西方墨點法（Western blot）  免疫螢光法（IFA）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 65, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
