  ('medical-tech-moex-21062', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '在檢體接種細胞後，並未產生明顯細胞病變（cytopathic effect），需要以血球吸附試驗（hemadsorption）偵 測出病毒的存在，這可能是下列何種病毒？ 腺病毒（Adenovirus） 呼吸道融合病毒（Respiratory syncytial virus） 副流行性感冒病毒（Parainfluenza virus） 輪狀病毒（Rotavirus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 69, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
